#include "services/Services.h"
#include <stdexcept>
TradeService::TradeService(InstrumentRepository& ir,TransactionRepository& tr,HoldingRepository& hr):instruments_(ir),transactions_(tr),holdings_(hr){}
void TradeService::buy(int pid,const std::string& sym,int qty,double price){ if(qty<=0||price<=0) throw std::invalid_argument("Quantity and price must be positive"); auto inst=instruments_.findBySymbol(sym); if(!inst) throw std::runtime_error("Instrument not found: "+sym); auto h=holdings_.find(pid,inst->id); int oldQty=h? h->quantity:0; double oldAvg=h? h->averagePrice:0.0; int newQty=oldQty+qty; double newAvg=((oldQty*oldAvg)+(qty*price))/newQty; holdings_.upsert({0,pid,inst->id,newQty,newAvg}); transactions_.add({0,pid,inst->id,"BUY",qty,price,""}); }
void TradeService::sell(int pid,const std::string& sym,int qty,double price){ if(qty<=0||price<=0) throw std::invalid_argument("Quantity and price must be positive"); auto inst=instruments_.findBySymbol(sym); if(!inst) throw std::runtime_error("Instrument not found: "+sym); auto h=holdings_.find(pid,inst->id); if(!h || h->quantity<qty) throw std::runtime_error("Insufficient holdings to sell"); holdings_.upsert({h->id,pid,inst->id,h->quantity-qty,h->averagePrice}); transactions_.add({0,pid,inst->id,"SELL",qty,price,""}); }
